// CSV 업로드 파일 검사(ds_freightList)
scwin.f_CsvValidation = async function () {
  // debugger;

  // csv 파일 열이 0개 일때 오류 반환
  if (ds_csv.getRowCount() == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    return false;
  }

  // 행 개수 세기
  let cntRow = ds_csv.getRowCount();
  let chkCount = 0;

  // 각 행 돌기
  for (var i = 0; i < ds_csv.getRowCount(); i++) {
    // 모든 열 비어있는지 확인 (수동으로 행 개수 세기)
    let colcnt = 0;
    for (var v = 0; v < ds_csv.getColumnCount(); v++) {
      if (ds_csv.getCellData(i, ds_csv.getColumnID(v)) == null || ds_csv.getCellData(i, ds_csv.getColumnID(v)) == '') {
        colcnt += 1;
      }
    }
    if (colcnt == scwin.columnNum) {
      cntRow = i - 1;
      break;
    }
    let err = "";
    // 파트너 여부 체크
    let partner = new String();
    partner = ds_csv.getCellData(i, ds_csv.getColumnID(2));
    if (partner == null) {
      partner = '';
      ds_csv.setCellData(i, ds_csv.getColumnID(2), '');
    }
    partner = partner.replace(/ /gi, "");
    let partnerYn = '';
    if (partner == 'Y' || partner == 'y') partnerYn = 'Y';else if (partner == "" || partner == null) partnerYn = 'N';else partnerYn = 'err';
    // 내부거래 여부 체크
    let customerCode = new String();
    customerCode = ds_csv.getCellData(i, ds_csv.getColumnID(5));
    if (customerCode == null) {
      customerCode = '';
      ds_csv.setCellData(i, ds_csv.getColumnID(5), '');
    }
    customerCode = customerCode.replace(/ /gi, "");
    let innerYn = false;
    if (customerCode == '109856' || customerCode == '내부' || customerCode == '내부거래' || customerCode.toUpperCase() == 'INTERNAL') {
      innerYn = true;
    }
    if (innerYn && partnerYn == 'Y') {
      err += "파트너인 경우, 내부거래 코드가 올 수 없습니다.";
    }
    console.log("for문 시작");
    console.log("ds_csv.getColumnCount():", ds_csv.getColumnCount());

    // 각 열 돌기
    for (var k = 0; k < ds_csv.getColumnCount(); k++) {
      // 			alert(ds_csv.getColumnID(k));
      // 모든 항 ' ',쉼표 제거
      let temp = new String();
      temp = ds_csv.getCellData(i, ds_csv.getColumnID(k));
      if (temp == null) {
        ds_csv.setCellData(i, ds_csv.getColumnID(k), '');
        temp = '';
      }
      temp = temp.replace(/ /gi, "");
      temp = temp.replace(/,/gi, "");
      temp = temp.toUpperCase(); // 대문자 처리

      console.log("ds_csv.getColumnID(k):", ds_csv.getColumnID(k));
      console.log("temp:", temp);
      console.log("kkk:", k);
      ds_csv.setCellData(i, ds_csv.getColumnID(k), temp);

      // debugger;

      switch (k) {
        case 0:
          // SEA/AIR
          if (temp == '' || !/^[SA]{1}$/.test(temp.trim())) {
            err += "'SEA/AIR'열에는 S나 A를 입력해주세요. ";
          }
          break;
        case 1:
          // EXP/IMP
          if (temp == '' || !/^[IE]{1}$/.test(temp.trim())) {
            err += "'EXP/IMP'열에는 I나 E를 입력해주세요. ";
          }
          break;
        case 2:
          // 파트너
          if (partnerYn == 'err') {
            err += "'파트너'열에는 파트너일 경우 Y, 아닐 경우 공백으로 입력해주세요. ";
          }
          break;
        case 3:
          // C/D
          if (partnerYn == 'Y' && !/^[CD]{1}$/.test(temp) || partnerYn == 'N' && temp != '') {
            err += "'C/D'열에는 파트너일 경우 C나 D, 아닐 경우 공백으로 입력해주세요. ";
          }
          break;
        case 4:
          // House B/L
          if (temp == '') {
            err += "House B/L을 입력해주세요. ";
          }
          break;
        case 5:
          // Customer Code
          if (temp == '') {
            err += "Customer Code를 입력해주세요. ";
          }
          break;
        case 6:
          // Freight Code
          if (temp == '') {
            err += "Freight Code를 입력해주세요. ";
          } else if (innerYn && (temp.charAt(temp.length - 1) == 'V' || temp.charAt(temp.length - 1) == 'K')) {
            err += "내부거래일 경우, 운임코드에 -V, -K의 코드는 올 수 없습니다. ";
          } else if (partnerYn != 'Y' && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != '' && ds_csv.getCellData(i, ds_csv.getColumnID(7)) != 'KRW' && ds_csv.getCellData(i, ds_csv.getColumnID(14)) == 'Y') {
            let c = temp.charAt(temp.length - 1);
            if (c == 'J' || c == 'V' || c == 'K') {
              err += "CUR이 KRW가 아니며 외화정산이 Y일 경우, 운임코드에 -J, -V, -K의 코드는 올 수 없습니다. ";
            }
          }
          break;
        case 7:
          // CUR
          if (temp == '') {
            err += "CUR를 입력해주세요. ";
          }
          break;
        case 8:
          // Amount  
          if (isNaN(temp)) {
            err += "'Amount'열은 숫자나 공백으로 입력해주세요. ";
          }
          break;
        case 9:
          // EX-RATE
          if (isNaN(temp)) {
            err += "'Ex-rate'열은 숫자나 공백으로 입력해주세요. ";
          }
          break;
        case 10:
          // Amount(원)
          if (isNaN(temp)) {
            err += "'Amount(원)'열은 숫자나 공백으로 입력해주세요. ";
          }
          break;
        case 11:
          // VAT
          if (isNaN(temp)) {
            err += "'VAT'열은 숫자나 공백으로 입력해주세요. ";
          }
          if (String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).charAt(String(ds_csv.getCellData(i, ds_csv.getColumnID(6))).length - 1) == 'V') {
            // 					ds_csv.getCellData(i, "vat") = ds_csv.getCellData(i, "amount") * 0.1;
            ds_csv.setCellData(i, ds_csv.getColumnID(11), ds_csv.getCellData(i, ds_csv.getColumnID(10)) * 0.1);
          }
          break;
        case 12:
          // Result Date
          if (temp == '' || isNaN(temp) || temp.length != 8) {
            err += "'Result Date'열은 날짜로 입력해주세요. ";
          } else if (scwin.f_JobCloseYn(temp) == -1) {
            err += "'Result Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
          }
          break;
        case 13:
          // Invoice 쪽 billing Date
          // 				if ( temp == '' || isNaN(temp) || temp.length != 8) {
          // 					err += "'Invoice Date'열은 날짜로 입력해주세요. ";
          // 				}
          // 				else if ( scwin.f_JobCloseYn(temp) == -1 ) {
          // 					err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
          // 				}
          break;
        case 14:
          // 외화 정산 -> Partner의 경우 모두 Y
          if (partnerYn == 'N' && temp != '' && temp != 'Y') {
            err += "'외화 정산'열은 Y나 공백으로 입력해주세요. ";
          }
          break;
        case 15:
          // 내부거래 코드
          if (innerYn) {
            if (temp == '') {
              err += "내부거래 코드를 입력해주세요. ";
            }
          } else {
            if (temp != '') {
              err += "Customer Code가 '109856'일 경우에만 내부거래 코드를 입력할 수 있습니다. ";
            }
          }
          break;
        case 16:
          // 요청범위
          if (!innerYn) {
            // 내부거래가 아닐 때만 검사
            if (temp == '') {
              err += "'요청범위'를 입력해주세요. (1~2) ";
            } else if (temp != '1' && temp != '2') {
              err += "'요청범위'는 1~2 사이의 숫자를 입력해주세요. ";
            } else if (temp == '2') {
              if (ds_csv.getCellData(i, ds_csv.getColumnID(13)) == '' || isNaN(ds_csv.getCellData(i, ds_csv.getColumnID(13))) || String(ds_csv.getCellData(i, ds_csv.getColumnID(13))).length != 8) {
                err += "'Invoice Date'열은 날짜로 입력해주세요. ";
              } else if (scwin.f_JobCloseYn(ds_csv.getCellData(i, ds_csv.getColumnID(13))) == -1) {
                err += "'Invoice Date'의 날짜는 결산이 완료된 과거로 설정될 수 없습니다. ";
              }
            }
          }
          break;
      } //switch 끝
    } //열끝

    console.log("for문 종료");

    //ds_err.AddRow();
    //ds_err.NameValue(i, "err") = err;
    ds_err.insertRow();
    ds_err.setCellData(i, "err", err);
    console.log("ds_err getRowJSON 데이터::", ds_err.getRowJSON(i));
    scwin.iii = i;

    //debugger;

    /////////////////////////
    if (err == '') {
      // 에러 없을 시 DB 유효값 조회

      if (innerYn) {
        //내부거래일 때 109856으로 값 바꿔주기.
        ds_csv.setCellData(i, ds_csv.getColumnID(5), '109856');
        ds_csv.setCellData(i, ds_csv.getColumnID(16), 0);
      }
      ds_RetrieveValidation.removeAll();
      ds_validation.removeAll();
      //ds_RetrieveValidation.ImportData(ds_csv.ExportData(i, 1, true)); //첫번째 인텍스는 가우스는 1부터, 웨스퀘어는 0부터
      //setJSON([ ... ]): ds_RetrieveValidation에 기존 데이터를 모두 지우고, 방금 가져온 1건의 행만 배열 형태로 담아 새로 채웁니다.
      //getRowJSON(): 기본적으로 삭제된 행을 제외한 현재 화면상의 데이터만 가져옵니다.
      //getAllJSON(): 삭제(Delete) 상태인 행까지 포함하여 가져옵니다.
      ds_RetrieveValidation.setJSON([ds_csv.getRowJSON(i)]);
      console.log("에러 없을 시 ds_csv.getRowJSON()::" + JSON.stringify(ds_csv.getRowJSON(i)));
      console.log("현재 ds_RetrieveValidation 전체 데이터::", ds_RetrieveValidation.getRowJSON(0));

      //tr_validation.Post();
      await $c.sbm.execute($p, sbm_validation);

      //서브미션에서 호출 하면 멈춤, 그래서 직접 스크립트로 호출([중요]현재 for문을 다돌고 이후단 수행하기 위한 방법)
      scwin.sbm_validation_submitdone();
    }
  } //행끝

  // 완료
  //ds_freightList.ImportData(ds_csv.ExportData(1, cntRow, true));
  for (var i = 0; i < cntRow; i++) {
    //ds_csv의 i번째 행 데이터 1건을 추출하여 ds_freightList의 기존 데이터 뒤에 추가(Append)하는 가장 효율적인 방식입니다.
    ds_freightList.setJSON([ds_csv.getRowJSON(i)], true);
  }
  for (var k = 0; k < ds_freightList.getRowCount(); k++) {
    ds_freightList.setCellData(k, "err", ds_err.getCellData(k, "err"));
  }
  console.log("ddddd");
  ds_err.removeAll();
  return true;
};
scwin.sbm_validation_submitdone = function (e) {
  let validationrowCnt = ds_validation.getRowCount();
  let arr = ["blNo", "custCd", "freightCd", "crcCd", "innerDept"];
  let arrMsg = ["House B/L", "Customer Code", "Freight Code", "CUR Code", "내부거래 코드"];
  let msg = "";
  if (validationrowCnt > 0) {
    for (let i = 0; i < arr.length; i++) {
      //웹스퀘어(WebSquare)로 변환할 때 가장 주의할 점은 **인덱스(Index)**입니다. 가우스는 1부터 시작하지만, 웹스퀘어는 0부터 시작합니다.
      // if (ds_validation.getCellData(1, arr[i]) != '1') {
      if (ds_validation.getCellData(0, arr[i]) != '1') {
        msg += arrMsg[i] + " 항목이 유효하지 않습니다. ";
      }
    }
    console.log("msgmsg:" + msg);
    console.log("scwin.iii:" + scwin.iii);
    ds_err.setCellData(scwin.iii, "err", msg); //for문 i인텍스 전역변수로 넘겨줌
  } else if (validationrowCnt == 0) {
    console.log("validationrowCnt:00:", validationrowCnt);
  } else {
    console.log("validationrowCnt::", validationrowCnt);
    scwin.sbm_validation_submiterror();
  }
};

