// 최종 실행 함수 (저장 버튼)
scwin.f_Save = async function () {
  if (scwin.editFlag) {
    await $c.gus.cfAlertMsg($p, "수정한 값이 존재합니다. 재검증 버튼을 눌러 재검증을 해주세요.");
    return;
  }
  //if (!ds_freightList.IsUpdated) {
  if (!ds_freightList.getModifiedIndex().length > 0) {
    await $c.gus.cfAlertMsg($p, "변경된 내역이 없습니다. 업로드 후 저장해주세요.");
    return;
  }
  if (!scwin.flag) {
    await $c.gus.cfAlertMsg($p, "수정되지 않은 오류 내역이 있습니다. '오류'열을 확인하고, 수정 후 재업로드 해주세요.");
    return;
  }

  // if (!cfConfirmMsg("저장하시겠습니까?")) {
  ret = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (ret == false) {
    return;
  }

  // 1. DB 값 받아오기
  for (var i = 0; i < ds_freightList.getRowCount(); i++) {
    ds_dbCodeRetrieve.removeAll();
    //ds_dbCodeRetrieve.ImportData(ds_freightList.ExportData(i, 1, true));
    ds_dbCodeRetrieve.setJSON([ds_freightList.getRowJSON(i)]);
    console.log("ds_freightList.getRowJSON()::" + JSON.stringify(ds_freightList.getRowJSON(i)));
    console.log("ds_dbCodeRetrieve.getRowJSON()::" + JSON.stringify([ds_dbCodeRetrieve.getRowJSON(0)]));
    console.log("ds_dbCodeRetrieve.getRowJSON():,,:", ds_dbCodeRetrieve.getRowJSON(0));
    await $c.sbm.execute($p, sbm_dbCodeRetrieve); //await 걸면 멈춤, 함수호출 방식으로 변경

    scwin.sbm_dbCodeRetrieve_submitdone(); //ev:submitdone 제거후 호출해야 에러 없음,직접 스크립트로 호출([중요]현재 for문을 다돌고 이후단 수행하기 위한 방법)
  }

  // 2. 각 데이터에 맞는 데이터셋으로 옮기기
  for (let i = 0; i < ds_freightList.getRowCount(); i++) {
    let SA = ds_freightList.getCellData(i, "seaAirCls");
    let IE = ds_freightList.getCellData(i, "expImp");
    let P = ds_freightList.getCellData(i, "partner");
    console.log("SASASASA:", SA);
    console.log("IEIEIEIE:", IE);
    console.log("PPPPP:", P);
    let temp; // 임시 데이터셋 자리
    let tempInv; // 임시 데이터셋 자리2
    if (SA == 'S') {
      // 해운
      if (IE == 'I') {
        // Import
        if (P == 'Y') {
          temp = ds_seaImpPartner;
          tempInv = ds_invoiceSIP;
        } else {
          temp = ds_seaImpBuying;
          tempInv = ds_invoiceSIB;
        }
      } else {
        // Export
        if (P == 'Y') {
          temp = ds_seaExpPartner;
          tempInv = ds_invoiceSEP;
        } else {
          temp = ds_seaExpBuying;
          tempInv = ds_invoiceSEB;
        }
      }
    } else {
      // 항공
      if (IE == 'I') {
        // Import
        if (P == 'Y') {
          temp = ds_airImpPartner;
          tempInv = ds_invoiceAIP;
        } else {
          temp = ds_airImpBuying;
          tempInv = ds_invoiceAIB;
        }
      } else {
        // Export
        if (P == 'Y') {
          temp = ds_airExpPartner;
          tempInv = ds_invoiceAEP;
        } else {
          temp = ds_airExpBuying;
          tempInv = ds_invoiceAEB;
        }
      }
    }

    //temp.AddRow();
    temp.insertRow();
    console.log("save odrNo:", ds_dbCodeList.getCellData(i, "odrNo"));
    temp.setCellData(temp.getRowCount() - 1, "odrNo", ds_dbCodeList.getCellData(i, "odrNo"));
    temp.setCellData(temp.getRowCount() - 1, "kcomcd", ds_dbCodeList.getCellData(i, "kcomcd"));
    temp.setCellData(temp.getRowCount() - 1, "seaAirCls", SA);
    temp.setCellData(temp.getRowCount() - 1, "blNo", ds_freightList.getCellData(i, "blNo"));
    temp.setCellData(temp.getRowCount() - 1, "mhno", ds_dbCodeList.getCellData(i, "mhno"));
    temp.setCellData(temp.getRowCount() - 1, "fareEngCd", ds_freightList.getCellData(i, "freightCd"));
    temp.setCellData(temp.getRowCount() - 1, "fareEngNm", ds_dbCodeList.getCellData(i, "fareEngNm"));
    temp.setCellData(temp.getRowCount() - 1, "fareGrpCd", ds_dbCodeList.getCellData(i, "fareGrpCd"));
    if (SA == 'S') {
      temp.setCellData(temp.getRowCount() - 1, "fareUnit", 'CASE');
    } else {
      temp.setCellData(temp.getRowCount() - 1, "fareUnit", '');
    }
    if (P == 'Y') {
      temp.setCellData(temp.getRowCount() - 1, "locPtnCls", '2');
    } else {
      temp.setCellData(temp.getRowCount() - 1, "locPtnCls", '1');
    }
    temp.setCellData(temp.getRowCount() - 1, "mblHblCls", "H");
    if (P == 'Y') {
      temp.setCellData(temp.getRowCount() - 1, "drcrCls", ds_freightList.getCellData(i, "cd"));
    } else {
      temp.setCellData(temp.getRowCount() - 1, "drcrCls", 'C');
    }
    if (SA == 'S') {
      temp.setCellData(temp.getRowCount() - 1, "ppccCls", ds_dbCodeList.getCellData(i, "ppccCls"));
    } else {
      temp.setCellData(temp.getRowCount() - 1, "ppccCls", '');
    }
    temp.setCellData(temp.getRowCount() - 1, "crcCd", ds_freightList.getCellData(i, "crcCd"));
    if (SA == 'S') {
      temp.setCellData(temp.getRowCount() - 1, "qty", 0);
    } else {
      temp.setCellData(temp.getRowCount() - 1, "qty", ds_dbCodeList.getCellData(i, "qty"));
    }
    if (SA == 'S') {
      temp.setCellData(temp.getRowCount() - 1, "grossWt", 0.0);
    } else {
      temp.setCellData(temp.getRowCount() - 1, "grossWt", ds_dbCodeList.getCellData(i, "grossWt"));
    }
    temp.setCellData(temp.getRowCount() - 1, "chgWt", 1);
    temp.setCellData(temp.getRowCount() - 1, "trfUpr", 0.0);
    temp.setCellData(temp.getRowCount() - 1, "exRate", ds_freightList.getCellData(i, "exRate"));
    if (SA == 'S') {
      temp.setCellData(temp.getRowCount() - 1, "exRateTyp", ds_dbCodeList.getCellData(i, "exRateTyp"));
    } else {
      temp.setCellData(temp.getRowCount() - 1, "exRateTyp", '');
    }
    temp.setCellData(temp.getRowCount() - 1, "prtnAmt", 0);
    temp.setCellData(temp.getRowCount() - 1, "rsltsStdDt", ds_freightList.getCellData(i, "resultDate"));
    if (ds_freightList.getCellData(i, "vat") > 0) {
      temp.setCellData(temp.getRowCount() - 1, "vatYn", 1);
    } else {
      temp.setCellData(temp.getRowCount() - 1, "vatYn", 0);
    }

    // Partner
    if (P == 'Y') {
      temp.setCellData(temp.getRowCount() - 1, "sellSeq", 0);
      temp.setCellData(temp.getRowCount() - 1, "bilgClntNo", ds_freightList.getCellData(i, "custCd"));
      temp.setCellData(temp.getRowCount() - 1, "bilgClntNm", ds_dbCodeList.getCellData(i, "bilgClntNm"));
      temp.setCellData(temp.getRowCount() - 1, "sellItemCd", ds_dbCodeList.getCellData(i, "sellItemCd"));
      temp.setCellData(temp.getRowCount() - 1, "sellUpr", 1);
      temp.setCellData(temp.getRowCount() - 1, "sellAmtFcrc", ds_freightList.getCellData(i, "amount"));
      if (ds_freightList.getCellData(i, "amountWon") != '') {
        temp.setCellData(temp.getRowCount() - 1, "sellAmt", ds_freightList.getCellData(i, "amountWon"));
      } else {
        temp.setCellData(temp.getRowCount() - 1, "sellAmt", ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate"));
      }
      temp.setCellData(temp.getRowCount() - 1, "vatAmt", ds_freightList.getCellData(i, "vat"));
    }
    // Buying
    else {
      temp.setCellData(temp.getRowCount() - 1, "pchsSeq", 0);
      temp.setCellData(temp.getRowCount() - 1, "pchsClntNo", ds_freightList.getCellData(i, "custCd"));
      temp.setCellData(temp.getRowCount() - 1, "pchsClntNm", ds_dbCodeList.getCellData(i, "pchsClntNm"));
      temp.setCellData(temp.getRowCount() - 1, "selpchItemCd", ds_dbCodeList.getCellData(i, "selpchItemCd")); //
      temp.setCellData(temp.getRowCount() - 1, "pchsUpr", 1);
      temp.setCellData(temp.getRowCount() - 1, "pchsAmtFcrc", ds_freightList.getCellData(i, "amount"));
      if (ds_freightList.getCellData(i, "amountWon") != '') {
        temp.setCellData(temp.getRowCount() - 1, "pchsAmt", ds_freightList.getCellData(i, "amountWon"));
      } else {
        temp.setCellData(temp.getRowCount() - 1, "pchsAmt", ds_freightList.getCellData(i, "amount") * ds_freightList.getCellData(i, "exRate"));
      }
      temp.setCellData(temp.getRowCount() - 1, "vat", ds_freightList.getCellData(i, "vat"));
      if (ds_freightList.getCellData(i, "innerDept") != '') {
        temp.setCellData(temp.getRowCount() - 1, "sellDeptCd", ds_freightList.getCellData(i, "innerDept"));
      } else {
        temp.setCellData(temp.getRowCount() - 1, "sellDeptCd", '');
      }
      if (ds_freightList.getCellData(i, "innerDept") != '') {
        temp.setCellData(temp.getRowCount() - 1, "sellDeptNm", ds_dbCodeList.getCellData(i, "sellDeptNm"));
      } else {
        temp.setCellData(temp.getRowCount() - 1, "sellDeptNm", '');
      }
      if (ds_freightList.getCellData(i, "innerDept") != '') {
        temp.setCellData(temp.getRowCount() - 1, "pchsTyp", '3');
      } else {
        temp.setCellData(temp.getRowCount() - 1, "pchsTyp", '1');
      }
    }

    // usdAmt 계산
    if (SA == 'S' && ds_dbCodeList.getCellData(i, "usdAmt") != 0) {
      if (P == 'Y') {
        temp.setCellData(temp.getRowCount() - 1, "usdAmt", Math.round(temp.getCellData(temp.getRowCount() - 1, "sellAmt") / ds_dbCodeList.getCellData(i, "usdAmt") * 100) / 100);
      } else {
        temp.setCellData(temp.getRowCount() - 1, "usdAmt", Math.round(temp.getCellData(temp.getRowCount() - 1, "pchsAmt") / ds_dbCodeList.getCellData(i, "usdAmt") * 100) / 100);
      }
    }

    // qty, grossWt 추가 계산
    if (SA == 'A' && IE == 'E' && P == 'Y') {
      temp.setCellData(temp.getRowCount() - 1, "qty", 0);
      temp.setCellData(temp.getRowCount() - 1, "grossWt", 0);
    }

    // Invoice 생성 관련 ds 설정
    //tempInv.ImportData(...): 추출된 1건의 데이터를 tempInv DataList에 넣습니다. (기본적으로 기존 데이터 뒤에 Append 됩니다.)
    //tempInv.ImportData(temp.ExportData(temp.CountRow, 1, true));
    tempInv.insertRow(); //asis는 addrow가 없어도 수행됨, 그래서 tobe 추가됨
    tempInv.setJSON([temp.getRowJSON(temp.getRowCount() - 1)]);
    console.log("temptemp getID:", temp.getID());
    console.log("tempInvtempInv getID:", tempInv.getID());
    console.log("temp.getRowJSON()::" + JSON.stringify(temp.getRowJSON(temp.getRowCount() - 1)));
    tempInv.setCellData(tempInv.getRowCount() - 1, "billingDate", ds_freightList.getCellData(i, "billingDate"));
    tempInv.setCellData(tempInv.getRowCount() - 1, "foreignCurSet", ds_freightList.getCellData(i, "foreignCurSet"));
    tempInv.setCellData(tempInv.getRowCount() - 1, "requestSize", ds_freightList.getCellData(i, "requestSize"));
    tempInv.setCellData(tempInv.getRowCount() - 1, "partner", P);
    if (IE == 'I') {
      tempInv.setCellData(tempInv.getRowCount() - 1, "expImp", 'I');
    } else {
      tempInv.setCellData(tempInv.getRowCount() - 1, "expImp", 'O');
    }
    console.log("tempInv.getAllJSON()::" + JSON.stringify([tempInv.getAllJSON(temp.getRowCount() - 1)]));
  } // ds 설정 끝

  // 3. tr 실행
  //tr_saveFreight.Post();
  $c.sbm.execute($p, sbm_saveFreight);
};
