scwin.gr_freightListcnt_onfilereadend = function (value) {
  // 모든 열 비어있는지 확인 (수동으로 행 개수 세기)
  let chkColumnNum = 0;
  for (let v = 0; v < ds_freightListcnt.getColumnCount(); v++) {
    console.log("ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(v)::", ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(v)));
    if (ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(v)) != null && ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(v)) != '') {
      // 값이 존재할 때 실행될 로직
      console.log("if문통과::", ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(v)));
      chkColumnNum += 1;
    }
  }
  console.log("chkColumnNum::", chkColumnNum);

  // 17개 갯수 체크(엑셀에서 헤더값은 무조건 있으므로 17번째(요청범위) 값 존재유무로 체크)
  console.log("ds_freightListcnt.getCellData(0, 16)::", ds_freightListcnt.getCellData(0, 16));
  let cellData = ds_freightListcnt.getCellData(0, 16);
  // 데이터가 없을 때 (null, undefined, "" 모두 포함)
  if (!cellData) {
    // 로드된 데이터의 열값이 17개가 아니면 오류 반환
    if (chkColumnNum != scwin.columnNum) {
      $c.gus.cfAlertMsg($p, "\n컬럼값이 상이합니다. [형식=" + scwin.columnNum + "개] 입력한 열 개수 => " + chkColumnNum + "\n업로드 양식을 다운로드후, 양식에 맞게 입력해주세요.");
      return false;
    }
  }

  // 17개 이상 갯수 체크(엑셀에서 헤더값은 무조건 있으므로 17번째(요청범위) 이후 값 존재유무로 체크)
  if (ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(17)) != null && ds_freightListcnt.getCellData(0, ds_freightListcnt.getColumnID(17)) != '') {
    // 로드된 데이터의 열값이 17개 이상이면 오류 반환
    if (chkColumnNum != scwin.columnNum) {
      $c.gus.cfAlertMsg($p, "\n컬럼값이 상이합니다. [형식=" + scwin.columnNum + "개] 입력한 열 개수 => " + chkColumnNum + "\n업로드 양식을 다운로드후, 양식에 맞게 입력해주세요.");
      return false;
    }
  }
  scwin.f_Import();
};
scwin.fn_setBgColor = function (data, formattedData, rowIndex, colIndex) {
  // 1. 모든 컬럼 개수 가져오기
  let colCount = ds_freightList.getColumnCount();
  let errValue = ds_freightList.getCellData(rowIndex, "err"); // 에러 컬럼 값 가져오기

  if (errValue !== "") {
    // 2. 루프를 돌며 모든 셀에 배경색 적용
    for (let i = 0; i < colCount; i++) {
      let colId = gr_freightList.getColumnID(i); // 인덱스로 컬럼 ID 추출
      // 특정 체크박스 컬럼들을 포함하여 모든 컬럼에 동일한 bgColor 적용
      gr_freightList.setCellBackgroundColor(rowIndex, colId, "yellow");
    }
  } else {
    // 2. 루프를 돌며 모든 셀에 배경색 적용
    for (let i = 0; i < colCount; i++) {
      let colId = gr_freightList.getColumnID(i); // 인덱스로 컬럼 ID 추출
      // 특정 체크박스 컬럼들을 포함하여 모든 컬럼에 동일한 bgColor 적용
      gr_freightList.setCellBackgroundColor(rowIndex, colId, "white");
    }
  }
  return data;
};
